// ── Service logos ─────────────────────────────────────────────────────────────

function getServiceLogo(name: string): string | null {
  const n = name.toLowerCase();
  if (n.includes("exa") || n.includes("search") || n.includes("similar") || n.includes("find")) return exaLogo;
  if (n.includes("fire") || n.includes("crawl") || n.includes("scrap")) return firecrawlLogo;
  if (n.includes("resend") || n.includes("email") || n.includes("send") || n.includes("mail")) return resendLogo;
  return null;
}

function ServiceLogo({ name, size = 24 }: { name: string; size?: number }) {
  const isFirecrawl = name.toLowerCase().includes("fire") || name.toLowerCase().includes("crawl");
  const logo = getServiceLogo(name);
  if (logo) {
    return (
      <img
        src={logo}
        alt={name}
        style={{ width: size, height: size, objectFit: isFirecrawl ? "contain" : "cover", borderRadius: "6px", display: "block", background: isFirecrawl ? "#fff" : "transparent", padding: isFirecrawl ? "3px" : 0 }}
      />
    );
  }
  // fallback: grid svg
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none">
      <rect x="2" y="2" width="5" height="5" rx="1" stroke="currentColor" strokeWidth="1.5"/>
      <rect x="9" y="2" width="5" height="5" rx="1" stroke="currentColor" strokeWidth="1.5"/>
      <rect x="2" y="9" width="5" height="5" rx="1" stroke="currentColor" strokeWidth="1.5"/>
      <rect x="9" y="9" width="5" height="5" rx="1" stroke="currentColor" strokeWidth="1.5"/>
    </svg>
  );
}

// ── Component ─────────────────────────────────────────────────────────────────

function AmetystConsole() {
  const { input } = useToolInfo<"ametyst-console">();

  // LLM-visible: which service is selected, whether key is set, and active wallet
  const [{ selectedServiceId, hasApiKey, walletId }, setState] = useWidgetState<{
    selectedServiceId: string | null;
    hasApiKey: boolean;
    walletId: string | null;
  }>({ selectedServiceId: null, hasApiKey: false, walletId: null });

  // UI-only panel state — never synced to LLM to avoid re-render loops
  const [openPanel, setOpenPanel] = useState<Panel>(null);

  // Ephemeral form state
  const [apiKey, setApiKey] = useState(input?.prefillApiKey ?? "");
  const [apiKeyDraft, setApiKeyDraft] = useState(input?.prefillApiKey ?? "");
  const [accessAmount, setAccessAmount] = useState("");
  const [walletStatus, setWalletStatus] = useState<"pending" | "approved" | "rejected" | null>(null);
  const [walletBalance, setWalletBalance] = useState<{ balance: number; spendingLimit: number } | null>(null);
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});

  // Tool hooks
  const {
    callTool: findServices,
    data: servicesData,
    isPending: servicesLoading,
  } = useCallTool("find-services");

  const {
    callTool: getBalance,
    data: balanceData,
    isPending: balanceLoading,
    isError: balanceError,
  } = useCallTool("get-balance");

  const {
    callTool: runService,
    data: runData,
    isPending: running,
    isSuccess: ran,
    isError: runError,
  } = useCallTool("spend");

  const {
    callTool: requestAccess,
    data: accessData,
    isPending: requesting,
    isSuccess: accessSent,
    isError: accessError,
  } = useCallTool("request-access");

  const {
    callTool: checkWallet,
    data: checkWalletData,
    isPending: checkingWallet,
    isError: checkWalletError,
  } = useCallTool("check-wallet");

  const sendFollowUp = useSendFollowUpMessage();


  // Reset field values when selected service changes
  useEffect(() => { setFieldValues({}); }, [selectedServiceId]);

  // Auto-load services on mount; reload balance when key is set
  useEffect(() => {
    findServices({});
    getBalance({ ...(apiKey ? { apiKey } : {}) });
  }, []);
  useEffect(() => {
    if (apiKey) getBalance({ apiKey });
  }, [apiKey]);

  // After a service run completes, update balance from remaining and prompt the LLM to relay the result
  useEffect(() => {
    if (ran) {
      const sc = runData?.structuredContent as { remaining?: number } | undefined;
      if (sc?.remaining != null) {
        setWalletBalance((prev) => prev ? { ...prev, balance: sc.remaining! } : null);
      }
      sendFollowUp(
        "The service returned results via the tool call above. Present the actual content from the results to the user — include titles, URLs, and the full text of each snippet exactly as returned. Do not paraphrase or summarise; output the real data."
      );
    }
  }, [ran]);

  // Store wallet ID and start polling when access request succeeds
  useEffect(() => {
    if (accessSent && accessData) {
      const wid = (accessData.structuredContent as { walletId?: string }).walletId;
      if (wid) {
        setState((prev) => ({ ...prev, walletId: wid }));
        setWalletStatus("pending");
      }
    }
  }, [accessSent]);

  // Update walletStatus and balance when check-wallet responds
  useEffect(() => {
    if (!checkWalletData) return;
    const sc = checkWalletData.structuredContent as { status?: string; spent?: number; spendingLimit?: number } | undefined;
    const status = sc?.status;
    if (status === "approved" || status === "rejected" || status === "pending") {
      setWalletStatus(status as "pending" | "approved" | "rejected");
    }
    if (status === "approved" && sc?.spendingLimit != null && sc?.spent != null) {
      setWalletBalance({ balance: sc.spendingLimit - sc.spent, spendingLimit: sc.spendingLimit });
    } else if (status !== "approved") {
      setWalletBalance(null);
    }
  }, [checkWalletData]);

  const services: Service[] = servicesData?.structuredContent?.services ?? [];
  const selected = services.find((s) => s.id === selectedServiceId) ?? null;
  const rawBal = balanceData?.structuredContent as { balance?: number; currency?: string; spendingLimit?: number } | undefined;
  const bal = (rawBal?.balance != null && rawBal?.currency && rawBal?.spendingLimit != null) ? { balance: rawBal.balance, currency: rawBal.currency, spendingLimit: rawBal.spendingLimit } : null;
  const effectiveBal = bal ?? (walletBalance ? { balance: walletBalance.balance, currency: "credits", spendingLimit: walletBalance.spendingLimit } : null);

  const togglePanel = (p: Panel) =>
    setOpenPanel((prev) => (prev === p ? null : p));

  const pickService = (id: string) =>
    setState((prev) => ({
      ...prev,
      selectedServiceId: prev.selectedServiceId === id ? null : id,
    }));


  // Spending bar
  const spendPct =
    effectiveBal ? Math.min(100, Math.round((1 - effectiveBal.balance / effectiveBal.spendingLimit) * 100)) : 0;
  const remaining = effectiveBal ? effectiveBal.balance : null;

  // ── Render ────────────────────────────────────────────────────────────────

  return (
    <div
      style={s.card}
      data-llm={`Service: ${selected?.name ?? "none"} | Panel: ${openPanel ?? "none"} | Key set: ${hasApiKey}`}
    >
      {/* ── Header ─────────────────────────────────────────────────────────── */}
      <div style={s.header}>
        <div style={s.logoMark}>
          <svg width="22" height="20" viewBox="0 0 22 20" fill="none">
            {/* Left crystal */}
            <path d="M5 18.5L2.5 12.5L5 4.5L8 12.5L6.5 18.5Z" fill="white" opacity="0.68"/>
            <path d="M5 4.5L8 12.5L6.5 18.5Z" fill="white" opacity="0.28"/>
            {/* Center crystal (tallest) */}
            <path d="M11 19.5L8 11.5L11 2L14 11.5L11 19.5Z" fill="white" opacity="0.98"/>
            <path d="M11 2L14 11.5L11 19.5Z" fill="white" opacity="0.24"/>
            {/* Right crystal */}
            <path d="M17 18.5L14.5 12.5L17 5.5L20 12.5L18.5 18.5Z" fill="white" opacity="0.80"/>
            <path d="M17 5.5L20 12.5L18.5 18.5Z" fill="white" opacity="0.28"/>
          </svg>
          Ametyst
        </div>

        <div style={s.pills}>
          <button
            style={s.pill(openPanel === "balance")}
            onClick={() => togglePanel("balance")}
          >
            {effectiveBal
              ? `${effectiveBal.balance.toLocaleString()} ${effectiveBal.currency}`
              : balanceLoading
              ? "…"
              : "Balance"}
          </button>
          <button
            style={s.pill(openPanel === "access")}
            onClick={() => togglePanel("access")}
          >
            Request Access
          </button>
          <button
            style={s.pill(openPanel === "apikey", !apiKey)}
            onClick={() => togglePanel("apikey")}
          >
            {apiKey ? "API Key ✓" : "API Key"}
          </button>
        </div>
      </div>

      {/* ── Spending strip ─────────────────────────────────────────────────── */}
      {effectiveBal && (
        <div style={s.spendingStrip}>
          <span style={{ color: tk.muted, fontSize: "11px", whiteSpace: "nowrap" }}>
            {remaining!.toLocaleString()} {effectiveBal!.currency} available
          </span>
          <div style={s.progressTrack}>
            <div
              style={{
                height: "100%",
                width: `${spendPct}%`,
                background: spendPct > 80 ? "#f59e0b" : tk.accent,
                borderRadius: "99px",
                transition: "width 0.3s",
              }}
            />
          </div>
          <span style={{ color: tk.muted, fontSize: "11px", whiteSpace: "nowrap" }}>
            {effectiveBal.spendingLimit.toLocaleString()} limit
          </span>
        </div>
      )}

      {/* ── Expandable panels ─────────────────────────────────────────────── */}

      {openPanel === "balance" && (
        <div style={s.panel}>
          {effectiveBal ? (
            <div>
              <div style={{ display: "flex", gap: "16px", marginBottom: "4px" }}>
                <div>
                  <div style={{ fontSize: "11px", color: tk.muted }}>Available</div>
                  <div style={{ fontSize: "20px", fontWeight: 700, color: tk.accent }}>
                    {effectiveBal.balance.toLocaleString()}
                    <span style={{ fontSize: "12px", color: tk.muted, marginLeft: "3px" }}>{effectiveBal.currency}</span>
                  </div>
                </div>
                <div>
                  <div style={{ fontSize: "11px", color: tk.muted }}>Spend limit</div>
                  <div style={{ fontSize: "20px", fontWeight: 700, color: tk.textMid }}>
                    {effectiveBal.spendingLimit.toLocaleString()}
                    <span style={{ fontSize: "12px", color: tk.muted, marginLeft: "3px" }}>{effectiveBal.currency}</span>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <p style={{ fontSize: "12px", color: tk.muted, margin: 0 }}>
              {balanceLoading ? "Loading…" : balanceError ? "Failed to load balance." : "No data yet."}
            </p>
          )}
          <button
            style={{ ...s.btnGhost, marginTop: "6px", paddingLeft: 0 }}
            onClick={() => getBalance({ ...(apiKey ? { apiKey } : {}) })}
            disabled={balanceLoading}
          >
            {balanceLoading ? "Refreshing…" : "↻ Refresh"}
          </button>
        </div>
      )}

      {openPanel === "access" && (
        <div style={s.panel}>
          <div style={{ fontSize: "12px", color: tk.textMid, marginBottom: "8px" }}>
            Request a wallet with a spending limit. An admin will approve it from the web app.
          </div>
          <label style={s.fieldLabel}>Credits to request</label>
          <input
            style={{ ...s.input, marginBottom: "10px" }}
            type="number"
            min="1"
            value={accessAmount}
            onChange={(e) => setAccessAmount(e.target.value)}
            placeholder="e.g. 100"
          />
          <div style={{ display: "flex", gap: "8px", marginBottom: "4px" }}>
            <button
              style={{ ...s.btnPrimary(!accessAmount || !apiKey || requesting), flex: 1 }}
              disabled={!accessAmount || !apiKey || requesting}
              onClick={() =>
                requestAccess({
                  apiKey,
                  spendingLimit: Number(accessAmount),
                })
              }
            >
              {requesting ? "Submitting…" : "Request Wallet"}
            </button>
            {walletId && (
              <button
                style={{ ...s.btnPrimary(checkingWallet), whiteSpace: "nowrap" }}
                disabled={checkingWallet}
                onClick={() => { if (walletId) checkWallet({ walletId }); }}
              >
                {checkingWallet ? "Checking…" : "Check Status"}
              </button>
            )}
            {checkWalletError && (
              <div style={{ fontSize: "11px", color: tk.red, marginTop: "4px" }}>
                Check failed. Try again.
              </div>
            )}
          </div>
          {!apiKey && (
            <div style={{ fontSize: "11px", color: tk.amber, marginTop: "6px" }}>
              Set your API key first.
            </div>
          )}
          {accessError && (
            <div style={s.errorBadge}>Request failed. Please try again.</div>
          )}
          {walletStatus === "pending" && (
            <div style={{ ...s.successBadge, background: tk.amberSoft, border: "1px solid #fcd34d", color: tk.amber }}>
              ⏳ Pending admin approval…
            </div>
          )}
          {walletStatus === "approved" && (
            <div style={s.successBadge}>✓ Wallet approved — ready to spend</div>
          )}
          {walletStatus === "rejected" && (
            <div style={s.errorBadge}>✗ Request rejected</div>
          )}
          {!walletStatus && accessSent && (accessData?.structuredContent as { walletId?: string })?.walletId && (
            <div style={s.successBadge}>
              ✓ Wallet created · ID: {(accessData!.structuredContent as { walletId: string }).walletId}
            </div>
          )}
        </div>
      )}

      {openPanel === "apikey" && (
        <div style={s.panel}>
          <div style={{ fontSize: "12px", color: tk.textMid, marginBottom: "8px" }}>
            Enter your Ametyst API key to authenticate requests.
          </div>
          <label style={s.fieldLabel}>API Key</label>
          <input
            style={{ ...s.input, marginBottom: "10px", fontFamily: "monospace" }}
            type="password"
            value={apiKeyDraft}
            onChange={(e) => setApiKeyDraft(e.target.value)}
            placeholder="amtst_…"
            autoComplete="off"
          />
          <button
            style={s.btnPrimary(!apiKeyDraft.trim())}
            disabled={!apiKeyDraft.trim()}
            onClick={() => {
              setApiKey(apiKeyDraft.trim());
              setState((prev) => ({ ...prev, hasApiKey: true }));
              setOpenPanel(null);
            }}
          >
            Save Key
          </button>
          {apiKey && (
            <button
              style={{ ...s.btnGhost, marginLeft: "8px", color: tk.red }}
              onClick={() => { setApiKey(""); setApiKeyDraft(""); setState((prev) => ({ ...prev, hasApiKey: false })); }}
            >
              Clear
            </button>
          )}
        </div>
      )}

      {/* ── Body ───────────────────────────────────────────────────────────── */}
      <div style={s.body}>

        {/* Service list */}
        <div style={s.sectionLabel}>
          {servicesLoading ? "Loading services…" : "Services"}
        </div>

        {!servicesLoading && services.length === 0 && (
          <div style={{
            padding: "20px 12px",
            textAlign: "center" as const,
            color: tk.muted,
            fontSize: "12.5px",
            border: `1px dashed ${tk.border}`,
            borderRadius: tk.radiusSm,
            marginBottom: "8px",
          }}>
            No services available yet.
            <br />
            <span style={{ fontSize: "11px" }}>Connect the Ametyst backend to load the catalog.</span>
          </div>
        )}

        {services.map((svc) => {
          const isSelected = svc.id === selectedServiceId;
          return (
            <div
              key={svc.id}
              style={s.serviceRow(isSelected)}
              onClick={() => pickService(svc.id)}
              data-llm={`${svc.name} · €${svc.cost} · ${svc.id}`}
            >
              {/* Logo avatar */}
              <div style={{
                width: "34px",
                height: "34px",
                borderRadius: "9px",
                overflow: "hidden",
                flexShrink: 0,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                background: getServiceLogo(svc.name) ? "transparent" : isSelected ? tk.accent : `${tk.accent}18`,
                color: isSelected ? "#fff" : tk.accent,
                boxShadow: isSelected ? `0 0 0 2px ${tk.accent}` : "none",
                transition: "all 0.15s",
              }}>
                <ServiceLogo name={svc.name} size={34} />
              </div>

              {/* Name + description */}
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontWeight: 600, fontSize: "13px", color: tk.text }}>
                  {svc.name}
                </div>
                <div style={{
                  fontSize: "11px",
                  color: tk.muted,
                  marginTop: "2px",
                  overflow: "hidden",
                  textOverflow: "ellipsis",
                  whiteSpace: "nowrap",
                }}>
                  {svc.description || svc.endpoint}
                </div>
              </div>

              {/* Cost badge */}
              <span style={{
                fontSize: "12px",
                fontWeight: 600,
                color: isSelected ? tk.accentText : tk.muted,
                background: isSelected ? "#ede9fe" : tk.surface,
                border: `1px solid ${isSelected ? "#c4b5fd" : tk.border}`,
                borderRadius: "7px",
                padding: "3px 8px",
                whiteSpace: "nowrap",
                flexShrink: 0,
                transition: "all 0.15s",
              }}>
                €{svc.cost}
              </span>
            </div>
          );
        })}

        {/* Selected service detail + run */}
        {selected && (
          <>
            <div style={s.divider} />

            <div style={s.detailCard}>
              <div style={s.detailHeader}>
                <div>
                  <div style={{ fontWeight: 600, fontSize: "13px" }}>{selected.name}</div>
                  <div style={{ fontSize: "11px", color: tk.muted, marginTop: "1px" }}>
                    {selected.endpoint}
                  </div>
                </div>
                <span
                  style={{
                    fontSize: "12px",
                    fontWeight: 600,
                    color: tk.accentText,
                    background: "#ede9fe",
                    border: `1px solid #c4b5fd`,
                    borderRadius: "7px",
                    padding: "3px 8px",
                  }}
                >
                  €{selected.cost}
                </span>
              </div>
              <div style={{ padding: "8px 12px", fontSize: "12px", color: tk.textMid, lineHeight: "1.5" }}>
                {selected.description}
              </div>
            </div>

            {/* Dynamic inputs from input_schema */}
            {(selected.inputSchema?.required ?? []).map((field) => {
              const prop = selected.inputSchema?.properties?.[field];
              const isLong = field === "query" || field === "text";
              return (
                <div key={field} style={{ marginBottom: "8px" }}>
                  <label style={s.fieldLabel}>
                    {field}{prop?.description ? ` — ${prop.description}` : ""}
                  </label>
                  {isLong ? (
                    <textarea
                      style={s.textarea}
                      value={fieldValues[field] ?? ""}
                      onChange={(e) => setFieldValues((prev) => ({ ...prev, [field]: e.target.value }))}
                      placeholder={prop?.description ?? field}
                    />
                  ) : (
                    <input
                      style={s.input}
                      value={fieldValues[field] ?? ""}
                      onChange={(e) => setFieldValues((prev) => ({ ...prev, [field]: e.target.value }))}
                      placeholder={prop?.description ?? field}
                    />
                  )}
                </div>
              );
            })}

            {(() => {
              const requiredFields = selected.inputSchema?.required ?? [];
              const allFilled = requiredFields.every((f) => fieldValues[f]?.trim());
              const params = Object.fromEntries(
                Object.entries(fieldValues).filter(([, v]) => v.trim())
              );
              return (
                <>
                  <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                    <button
                      style={s.btnPrimary(!allFilled || running)}
                      disabled={!allFilled || running}
                      onClick={() =>
                        runService({
                          endpointUrl: selected.endpoint,
                          apiKey,
                          walletId: walletId ?? undefined,
                          params,
                          amount: selected.cost,
                        })
                      }
                    >
                      {running ? "Running…" : `▶ Run ${selected.name}`}
                    </button>
                  </div>
                  {runError && (
                    <div style={s.errorBadge}>Execution failed. Please try again.</div>
                  )}
                </>
              );
            })()}

            {ran && runData && (() => {
              const output = runData.structuredContent.output as Record<string, unknown> | null;
              // Exa Search / Find Similar: { results: [{ title, url, publishedDate?, score? }] }
              const results = output?.results as Array<{ title: string; url: string; publishedDate?: string; score?: number }> | undefined;
              // Firecrawl Scrape: { data: { markdown, metadata: { title } } }
              const scrape = output?.data as { markdown?: string; metadata?: { title?: string } } | undefined;
              return (
                <div style={{ marginTop: "12px" }}>
                  {results?.length ? (
                    results.map((r, i) => (
                      <div
                        key={i}
                        style={{
                          padding: "9px 11px",
                          border: `1px solid ${tk.border}`,
                          borderRadius: tk.radiusSm,
                          marginBottom: "6px",
                          background: tk.surface,
                        }}
                        data-llm={`Result ${i + 1}: ${r.title} — ${r.url}`}
                      >
                        <div style={{ fontWeight: 500, fontSize: "12.5px", marginBottom: "2px" }}>
                          {r.title}
                        </div>
                        <div style={{ fontSize: "11px", color: tk.accent, wordBreak: "break-all" }}>
                          {r.url}
                        </div>
                        {(r.publishedDate || r.score != null) && (
                          <div style={{ fontSize: "11px", color: tk.muted, marginTop: "2px" }}>
                            {r.publishedDate ? new Date(r.publishedDate).toLocaleDateString() : `score: ${r.score?.toFixed(2)}`}
                          </div>
                        )}
                      </div>
                    ))
                  ) : scrape?.markdown ? (
                    <div style={s.outputBox}>
                      {scrape.metadata?.title && (
                        <div style={{ fontWeight: 600, marginBottom: "6px" }}>{scrape.metadata.title}</div>
                      )}
                      {scrape.markdown}
                    </div>
                  ) : (
                    <div style={s.outputBox}>{formatToolOutput(output)}</div>
                  )}
                  <div style={{ fontSize: "11px", color: tk.muted, marginTop: "4px" }}>
                    Sending results to chat…
                  </div>
                </div>
              );
            })()}
          </>
        )}
      </div>
    </div>
  );
}

export default AmetystConsole;

mountWidget(<AmetystConsole />);
